node -e "
const os = require('os');
const { execSync } = require('child_process');

const n = os.cpus().length;
const load = os.loadavg();
const cpu = Math.min(100, Math.round((load[0] / n) * 100));

const t = os.totalmem();
const f = os.freemem();
const usedMb = Math.round((t - f) / 1024 / 1024);
const totalMb = Math.round(t / 1024 / 1024);
const memPct = Math.round(((t - f) / t) * 100);

let disk = { usedGb: 0, totalGb: 0, percent: 0 };
try {
  const o = execSync('df -k /').toString();
  const lines = o.trim().split(String.fromCharCode(10));
  if (lines[1]) {
    const P = lines[1].split(/\\s+/);
    const totalK = parseInt(P[1], 10);
    const usedK = parseInt(P[2], 10);
    disk = {
      usedGb: Math.round((usedK / 1024 / 1024) * 100) / 100,
      totalGb: Math.round((totalK / 1024 / 1024) * 100) / 100,
      percent: totalK > 0 ? Math.round((usedK / totalK) * 100) : 0
    };
  }
} catch (e) {}

const upSec = os.uptime();
const days = Math.floor(upSec / 86400);
const hrs = Math.floor((upSec % 86400) / 3600);
const mins = Math.floor((upSec % 3600) / 60);
const secs = Math.floor(upSec % 60);
const uptime = days + 'd ' + hrs + 'h ' + mins + 'm ' + secs + 's';

const hostname = os.hostname();
const arch = os.arch() + ' (' + os.platform() + ')';
const freeMem = os.freemem();
const freeMemGb = Math.round((freeMem / 1024 / 1024 / 1024) * 100) / 100;
const totalMemGb = Math.round((t / 1024 / 1024 / 1024) * 100) / 100;

const result = {
  metrics: {
    cpu: { percent: cpu },
    memory: { usedMb, totalMb, percent: memPct },
    disk: disk,
    n8nWorkers: { active: 0, idle: 0, busy: 0, total: 0 }
  },
  workers: [{
    name: hostname,
    id: hostname,
    status: 'online',
    averageLoad: Math.round(load[0] * 100) / 100,
    freeMemoryGb: freeMemGb,
    totalMemoryGb: totalMemGb,
    uptime: uptime,
    arch: arch,
    n8nVersion: '',
    currentJobs: 0,
    cpuUsage: cpu,
    memoryUsage: memPct,
    hostMemory: {
      totalGb: totalMemGb,
      freeGb: freeMemGb
    },
    processMemory: {
      rss: 0,
      heapTotal: 0,
      heapUsed: 0
    },
    networkInterfaces: []
  }],
  history: []
};

console.log(JSON.stringify(result));
"

parameters.jsCode:
const serverItem = $('Coletar métricas do servidor').first();
const execItem = $('Buscar execuções n8n (running)').first();

// Parse server metrics from stdout
let serverData;
try {
  const raw = serverItem.json.stdout || '';
  serverData = JSON.parse(raw.trim());
} catch (e) {
  serverData = { metrics: { cpu: { percent: 0 }, memory: { usedMb: 0, totalMb: 0, percent: 0 }, disk: { usedGb: 0, totalGb: 0, percent: 0 }, n8nWorkers: { active: 0, idle: 0, busy: 0, total: 0 } }, workers: [], history: [] };
}

// Parse n8n executions
let runningCount = 0;
try {
  const execData = execItem.json;
  if (execData && execData.data && Array.isArray(execData.data)) {
    runningCount = execData.data.filter(e => e.status === 'running').length;
  }
} catch (e) {}

// Update workers info
serverData.metrics.n8nWorkers = {
  active: runningCount > 0 ? 1 : 1,
  idle: runningCount > 0 ? 0 : 1,
  busy: runningCount > 0 ? 1 : 0,
  total: 1
};

// Update worker currentJobs
if (serverData.workers && serverData.workers.length > 0) {
  serverData.workers[0].currentJobs = runningCount;
  serverData.workers[0].n8nVersion = $env.N8N_VERSION || '';
}

return [{ json: serverData }];
